import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import Navbar from "../components/Navbar";

export default function LoginPage() {
  const [role, setRole] = useState("RESIDENT");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const data = await login(username, password);
      if (data.role !== role) {
        setError(`This account is registered as ${data.role}, not ${role}. Redirecting to the correct dashboard.`);
      }
      navigate(data.role === "ADMIN" ? "/admin" : "/resident");
    } catch (err) {
      setError(err.response?.data?.message || "Invalid username or password.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <Navbar />
      <div className="container" style={{ maxWidth: 440, paddingTop: 60 }}>
        <div className="card">
          <h1 className="page-title">Log in</h1>
          <p className="page-subtitle">Choose your role, then sign in to your dashboard.</p>

          <div className="role-toggle">
            <div
              className={`role-toggle-btn ${role === "RESIDENT" ? "active" : ""}`}
              onClick={() => setRole("RESIDENT")}
            >
              Resident
            </div>
            <div
              className={`role-toggle-btn ${role === "ADMIN" ? "active" : ""}`}
              onClick={() => setRole("ADMIN")}
            >
              Apartment Admin
            </div>
          </div>

          {error && <div className="alert-banner">{error}</div>}

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Username</label>
              <input value={username} onChange={(e) => setUsername(e.target.value)} required />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <button className="btn btn-primary btn-block" disabled={loading}>
              {loading ? "Signing in..." : `Log in as ${role === "ADMIN" ? "Admin" : "Resident"}`}
            </button>
          </form>

          <p style={{ marginTop: 16, fontSize: 13, color: "#64748b", textAlign: "center" }}>
            No account? <Link to="/register" style={{ color: "#0e7490", fontWeight: 600 }}>Register here</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
